import{_ as n,o as a,c as p,a3 as e}from"./chunks/framework.B2-APVWH.js";const h=JSON.parse('{"title":"Autopilot","description":"","frontmatter":{},"headers":[],"relativePath":"scenarios/autopilot.md","filePath":"scenarios/autopilot.md"}'),i={name:"scenarios/autopilot.md"};function l(t,s,o,c,r,d){return a(),p("div",null,[...s[0]||(s[0]=[e(`<h1 id="autopilot" tabindex="-1">Autopilot <a class="header-anchor" href="#autopilot" aria-label="Permalink to &quot;Autopilot&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Agents: <code>@autopilot</code> · Complexity: Medium-High</p></div><p>Autonomous iterative development using a PRD as source of truth and progress tracking between iterations.</p><h2 id="mvp-overnight" tabindex="-1">MVP from PRD (Overnight Build) <a class="header-anchor" href="#mvp-overnight" aria-label="Permalink to &quot;MVP from PRD (Overnight Build) {#mvp-overnight}&quot;">​</a></h2><p><strong>Goal:</strong> Build an entire MVP overnight from a PRD, unattended.</p><p><strong>Agents involved:</strong> <code>/prd</code> → <code>@autopilot</code> (10 iterations) → <code>/verify</code></p><h3 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Evening: Setup (15 min)</span></span>
<span class="line"><span>──────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: /prd Task management app with Kanban board, drag-and-drop, and user auth</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /prd generates:</span></span>
<span class="line"><span>  → docs/PRD-task-manager.md</span></span>
<span class="line"><span>  → 8 user stories with Gherkin acceptance criteria</span></span>
<span class="line"><span>  → Issue breakdown: 7 tasks (S-M sized)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User reviews PRD, adjusts if needed.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: /autopilot docs/PRD-task-manager.md --max-iterations=10</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @autopilot initializes:</span></span>
<span class="line"><span>  → Creates .claude/autopilot/progress.md</span></span>
<span class="line"><span>  → Extracts 7 tasks from PRD</span></span>
<span class="line"><span>  → Creates git restore point</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteration 1: Data models</span></span>
<span class="line"><span>  → Creates Prisma schema (User, Board, Column, Task)</span></span>
<span class="line"><span>  → Runs prisma generate</span></span>
<span class="line"><span>  → ✓ DONE — commits, updates progress.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteration 2: API endpoints</span></span>
<span class="line"><span>  → Creates REST CRUD for boards, columns, tasks</span></span>
<span class="line"><span>  → Adds validation with Zod</span></span>
<span class="line"><span>  → Runs tsc --noEmit</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteration 3: Authentication</span></span>
<span class="line"><span>  → JWT login/register endpoints</span></span>
<span class="line"><span>  → Auth middleware</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteration 4: Frontend layout</span></span>
<span class="line"><span>  → Kanban board component</span></span>
<span class="line"><span>  → Column and task card components</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteration 5: Drag and drop</span></span>
<span class="line"><span>  → Integrates dnd-kit / sortable</span></span>
<span class="line"><span>  → Updates task position via API</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteration 6: User dashboard</span></span>
<span class="line"><span>  → Board list, create board flow</span></span>
<span class="line"><span>  → Protected routes</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Iteration 7: Tests</span></span>
<span class="line"><span>  → Unit tests for services</span></span>
<span class="line"><span>  → Integration tests for API</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  All tasks DONE → writes AUTOPILOT_COMPLETE to progress.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Next morning: User checks progress.md and git log.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: /verify</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /verify confirms:</span></span>
<span class="line"><span>  → tsc: 0 errors</span></span>
<span class="line"><span>  → Tests: 24/24 passing</span></span>
<span class="line"><span>  → Build: success</span></span></code></pre></div><hr><h2 id="db-migration" tabindex="-1">Database Migration (PostgreSQL to MySQL) <a class="header-anchor" href="#db-migration" aria-label="Permalink to &quot;Database Migration (PostgreSQL to MySQL) {#db-migration}&quot;">​</a></h2><p><strong>Goal:</strong> Migrate an existing project from PostgreSQL to MySQL.</p><p><strong>Command:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/autopilot docs/PRD-db-migration.md --max-iterations=15 --model=claude-opus-4-6</span></span></code></pre></div><p><strong>What happens:</strong></p><ol><li><code>@autopilot</code> reads PRD with migration requirements</li><li>Each iteration handles one migration task:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Iteration 1: Update Prisma provider</span></span>
<span class="line"><span>  → Change provider from &quot;postgresql&quot; to &quot;mysql&quot;</span></span>
<span class="line"><span>  → Adjust data types (TEXT → LONGTEXT, JSONB → JSON)</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iteration 2: Fix schema incompatibilities</span></span>
<span class="line"><span>  → PostgreSQL arrays → JSON columns</span></span>
<span class="line"><span>  → Enum handling differences</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iteration 3: Update seed scripts</span></span>
<span class="line"><span>  → Adjust SQL syntax for MySQL</span></span>
<span class="line"><span>  → Date format changes</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iteration 4: Update queries</span></span>
<span class="line"><span>  → Replace PostgreSQL-specific operators</span></span>
<span class="line"><span>  → ILIKE → LOWER() + LIKE</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iteration 5: Update Docker Compose</span></span>
<span class="line"><span>  → Replace postgres image with mysql</span></span>
<span class="line"><span>  → Update env vars (DATABASE_URL)</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iteration 6: Run and fix tests</span></span>
<span class="line"><span>  → Fix 3 failing tests (date comparison)</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iteration 7: Integration testing</span></span>
<span class="line"><span>  → Full CRUD test against MySQL</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>All tasks DONE → AUTOPILOT_COMPLETE</span></span></code></pre></div><hr><h2 id="devcontainer" tabindex="-1">Feature Build with Script Mode (DevContainer) <a class="header-anchor" href="#devcontainer" aria-label="Permalink to &quot;Feature Build with Script Mode (DevContainer) {#devcontainer}&quot;">​</a></h2><p><strong>Goal:</strong> Build a notification system using script mode for maximum quality.</p><p><strong>Agents involved:</strong> <code>/prd</code> → <code>scripts/autopilot.sh</code> (in DevContainer)</p><h3 id="workflow-1" tabindex="-1">Workflow <a class="header-anchor" href="#workflow-1" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Setup: DevContainer (5 min)</span></span>
<span class="line"><span>───────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Copy devcontainer config</span></span>
<span class="line"><span>cp templates/autopilot/devcontainer.json .devcontainer/devcontainer.json</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Open in VS Code → &quot;Reopen in Container&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Inside container terminal:</span></span>
<span class="line"><span>claude</span></span>
<span class="line"><span>&gt; /prd Real-time notification system with WebSocket, in-app and email</span></span>
<span class="line"><span>&gt; exit</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Run autopilot (script mode — true context reset)</span></span>
<span class="line"><span>./scripts/autopilot.sh docs/PRD-notifications.md \\</span></span>
<span class="line"><span>  --max-iterations=12 \\</span></span>
<span class="line"><span>  --model=claude-opus-4-6 \\</span></span>
<span class="line"><span>  --dangerously-skip-permissions</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Execution: Unattended (2-3 hours)</span></span>
<span class="line"><span>──────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Each iteration:</span></span>
<span class="line"><span>  1. Claude starts fresh (zero context)</span></span>
<span class="line"><span>  2. Reads PRD + progress.md</span></span>
<span class="line"><span>  3. Finds next PENDING task</span></span>
<span class="line"><span>  4. Implements it fully</span></span>
<span class="line"><span>  5. Updates progress.md</span></span>
<span class="line"><span>  6. Commits and exits</span></span>
<span class="line"><span>  7. Script kills process, starts next iteration</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  === Autopilot: Iteration 1 of 12 ===</span></span>
<span class="line"><span>  Task: WebSocket server setup</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  === Autopilot: Iteration 2 of 12 ===</span></span>
<span class="line"><span>  Task: Notification data models</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  === Autopilot: Iteration 8 of 12 ===</span></span>
<span class="line"><span>  Task: Email integration (SendGrid)</span></span>
<span class="line"><span>  → BLOCKED (missing API key in .env)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  === Autopilot: Iteration 9 of 12 ===</span></span>
<span class="line"><span>  Task: Frontend notification bell</span></span>
<span class="line"><span>  → ✓ DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Result: Check progress</span></span>
<span class="line"><span>──────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>cat .claude/autopilot/progress.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Tasks: 9 DONE, 1 BLOCKED, 0 PENDING</span></span>
<span class="line"><span>  Iterations used: 11/12</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Fix BLOCKED task manually, then resume:</span></span>
<span class="line"><span>./scripts/autopilot.sh docs/PRD-notifications.md</span></span></code></pre></div><hr><h2 id="parallel-worktrees" tabindex="-1">Parallel Features with Git Worktrees <a class="header-anchor" href="#parallel-worktrees" aria-label="Permalink to &quot;Parallel Features with Git Worktrees {#parallel-worktrees}&quot;">​</a></h2><p><strong>Goal:</strong> Build two independent features simultaneously overnight.</p><h3 id="workflow-2" tabindex="-1">Workflow <a class="header-anchor" href="#workflow-2" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Setup: Create worktrees</span></span>
<span class="line"><span>───────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>git worktree add ../project-auth -b feature/auth</span></span>
<span class="line"><span>git worktree add ../project-billing -b feature/billing</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Terminal 1:</span></span>
<span class="line"><span>cd ../project-auth</span></span>
<span class="line"><span>./scripts/autopilot.sh docs/PRD-auth.md \\</span></span>
<span class="line"><span>  --max-iterations=10 --dangerously-skip-permissions</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Terminal 2:</span></span>
<span class="line"><span>cd ../project-billing</span></span>
<span class="line"><span>./scripts/autopilot.sh docs/PRD-billing.md \\</span></span>
<span class="line"><span>  --max-iterations=10 --dangerously-skip-permissions</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Both run in parallel, each with isolated state</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Result: Next morning</span></span>
<span class="line"><span>────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Check auth progress</span></span>
<span class="line"><span>cat ../project-auth/.claude/autopilot/progress.md</span></span>
<span class="line"><span>  → 6/6 tasks DONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Check billing progress</span></span>
<span class="line"><span>cat ../project-billing/.claude/autopilot/progress.md</span></span>
<span class="line"><span>  → 7/8 tasks DONE, 1 BLOCKED</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Merge results</span></span>
<span class="line"><span>cd ../project-auth &amp;&amp; git checkout main &amp;&amp; git merge feature/auth</span></span>
<span class="line"><span>cd ../project-billing &amp;&amp; git checkout main &amp;&amp; git merge feature/billing</span></span></code></pre></div><hr><h2 id="quick-tips" tabindex="-1">Quick Tips <a class="header-anchor" href="#quick-tips" aria-label="Permalink to &quot;Quick Tips&quot;">​</a></h2><h3 id="when-to-use-plugin-mode-vs-script-mode" tabindex="-1">When to Use Plugin Mode vs Script Mode <a class="header-anchor" href="#when-to-use-plugin-mode-vs-script-mode" aria-label="Permalink to &quot;When to Use Plugin Mode vs Script Mode&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plugin mode (/autopilot):</span></span>
<span class="line"><span>  ✓ Quick features (&lt; 5 tasks)</span></span>
<span class="line"><span>  ✓ Attended sessions</span></span>
<span class="line"><span>  ✓ When you want to monitor progress live</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Script mode (scripts/autopilot.sh):</span></span>
<span class="line"><span>  ✓ Complex features (10+ tasks)</span></span>
<span class="line"><span>  ✓ Overnight unattended runs</span></span>
<span class="line"><span>  ✓ Migrations and large refactors</span></span>
<span class="line"><span>  ✓ When quality degrades in long sessions</span></span></code></pre></div><h3 id="writing-good-prds-for-autopilot" tabindex="-1">Writing Good PRDs for Autopilot <a class="header-anchor" href="#writing-good-prds-for-autopilot" aria-label="Permalink to &quot;Writing Good PRDs for Autopilot&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ DO: Include clear acceptance criteria per feature</span></span>
<span class="line"><span>✓ DO: Break work into small, independent tasks</span></span>
<span class="line"><span>✓ DO: Specify test requirements</span></span>
<span class="line"><span>✓ DO: Define the tech stack and patterns to follow</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ DON&#39;T: Leave requirements vague (&quot;make it fast&quot;)</span></span>
<span class="line"><span>✗ DON&#39;T: Include subjective design decisions</span></span>
<span class="line"><span>✗ DON&#39;T: Combine unrelated features in one PRD</span></span>
<span class="line"><span>✗ DON&#39;T: Skip the issue breakdown section</span></span></code></pre></div><hr><h2 id="related-scenarios" tabindex="-1">Related Scenarios <a class="header-anchor" href="#related-scenarios" aria-label="Permalink to &quot;Related Scenarios&quot;">​</a></h2><ul><li><a href="/scenarios/planning.html">Planning</a> - Create the plan before autopilot</li><li><a href="/scenarios/workflows.html">Workflows</a> - Manual multi-agent coordination</li><li><a href="/scenarios/migration.html">Migration</a> - Migration-specific scenarios</li></ul>`,36)])])}const g=n(i,[["render",l]]);export{h as __pageData,g as default};
